function Footer() {
  return (
    <footer className="bg-gray-900 text-white py-6 mt-20">
      <div className="max-w-6xl mx-auto px-4 flex flex-col sm:flex-row justify-between items-center text-center sm:text-left">
        <p className="text-sm">&copy; {new Date().getFullYear()} James Salls Roofing & Remodeling. All rights reserved.</p>
        <p className="text-sm mt-2 sm:mt-0">
          Built by <span className="font-semibold">Otis Guess</span>
        </p>
      </div>
    </footer>
  );
}

export default Footer;
